function solve(nums) {
  const n = nums.length;
  const memo = {};

  function dfs(index, a_xor, b_and, c_xor) {
    const key = [index, a_xor, b_and, c_xor];
    if (memo[key]) return memo[key];

    if (index === n) {
      return a_xor + b_and + c_xor;
    }

